int plp_aperta_portmod_lane_connection_t_init(int unit, portmod_lane_connection_t* portmod_lane_connection);


/*!
 * @struct portmod_phy_core_info_s
 * @brief Core information structure for external phy db
 */
typedef struct portmod_phy_core_info_s {
    plp_aperta_phymod_core_access_t core_access; /**< core access */
} portmod_phy_core_info_t;

